// Extract the text content from Claude's response
const response = $input.first().json;
const rawText = response.content?.[0]?.text ?? '';

// Strip any accidental markdown fences
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch (e) {
  // If JSON parse fails, return a structured error so the frontend shows it
  return [{
    json: {
      error: true,
      message: 'Failed to parse Claude response',
      raw: rawText.slice(0, 500)
    }
  }];
}

// Ensure required top-level fields exist
data.company_name    = data.company_name    ?? 'Unknown';
data.employees       = data.employees       ?? 'Unknown';
data.ownership       = data.ownership       ?? 'Unknown';
data.estimated_plants = data.estimated_plants ?? (data.plants?.length ?? 0).toString();
data.plants          = Array.isArray(data.plants) ? data.plants : [];

// Sanitize each plant entry
data.plants = data.plants.map((p, i) => ({
  parent_company: p.parent_company ?? data.company_name,
  company_name:   p.company_name   ?? data.company_name,
  city_state:     p.city_state     ?? '—',
  products:       p.products       ?? '—',
  final_product:  p.final_product  ?? '—',
  lat:  typeof p.lat === 'number' ? p.lat : null,
  lng:  typeof p.lng === 'number' ? p.lng : null,
}));

return [{ json: data }];
